-- Phase 3: Vocabulary Building
-- Topic: Word Formation (100 questions)
-- Level: intermediate (A2)
-- Distribution: 40 easy, 40 medium, 20 hard
-- Subtopics: Prefixes (25Q), Suffixes (25Q), Root Words (25Q), Compound Words (25Q)

INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- Subtopic 1: Prefixes (un-, re-, pre-, dis-) (25Q) - 10 easy, 10 medium, 5 hard
('foundation', 'word-formation', 'intermediate', 'Add the prefix "un-" to "happy". What does "unhappy" mean?', '["Not happy", "Very happy", "Always happy", "Sometimes happy"]', 0, 'Prefix "un-": Means "not" or "opposite of". Unhappy = not happy. The prefix "un-" reverses the meaning.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Add the prefix "re-" to "write". What does "rewrite" mean?', '["Write again", "Not write", "Before write", "Write badly"]', 0, 'Prefix "re-": Means "again". Rewrite = write again. The prefix "re-" indicates repetition.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Add the prefix "pre-" to "view". What does "preview" mean?', '["View before", "View again", "Not view", "View badly"]', 0, 'Prefix "pre-": Means "before". Preview = view before (see something before others). The prefix "pre-" indicates time before.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Add the prefix "dis-" to "like". What does "dislike" mean?', '["Not like", "Like very much", "Like again", "Like before"]', 0, 'Prefix "dis-": Means "not" or "opposite of". Dislike = not like or hate. The prefix "dis-" reverses meaning.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: un + lock = ?', '["Unlock", "Relock", "Prelock", "Dislock"]', 0, 'Word formation: "un-" + "lock" = "unlock". This means to open or reverse the action of locking.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: re + read = ?', '["Reread", "Unread", "Preread", "Disread"]', 0, 'Word formation: "re-" + "read" = "reread". This means to read again.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: pre + test = ?', '["Pretest", "Retest", "Untest", "Distest"]', 0, 'Word formation: "pre-" + "test" = "pretest". This means a test given before the main test.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: dis + agree = ?', '["Disagree", "Reagree", "Unagree", "Preagree"]', 0, 'Word formation: "dis-" + "agree" = "disagree". This means to not agree or have a different opinion.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What does "unsafe" mean?', '["Not safe", "Very safe", "Safe again", "Safe before"]', 0, 'Prefix "un-": "Unsafe" = not safe or dangerous. The prefix "un-" creates the opposite meaning.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What does "return" mean?', '["Come back", "Not turn", "Turn before", "Turn badly"]', 0, 'Prefix "re-": "Return" = come back or go back. The prefix "re-" indicates going back.', 'easy'),

('foundation', 'word-formation', 'intermediate', 'Add the correct prefix to make the opposite: ____ appear (to become invisible)', '["Dis", "Re", "Pre", "Un"]', 0, 'Prefix choice: "Disappear" means to become invisible or vanish. "Dis-" creates the opposite of appear.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Add the correct prefix: ____ heat (to heat again)', '["Re", "Un", "Pre", "Dis"]', 0, 'Prefix choice: "Reheat" means to heat again. "Re-" indicates repetition of the action.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Add the correct prefix: ____ paid (not yet paid)', '["Un", "Re", "Pre", "Dis"]', 0, 'Prefix choice: "Unpaid" means not paid or still owed. "Un-" indicates negation.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Add the correct prefix: ____ school (before school)', '["Pre", "Re", "Un", "Dis"]', 0, 'Prefix choice: "Preschool" means education before regular school. "Pre-" indicates time before.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "rebuild" mean?', '["Build again", "Not build", "Build before", "Build badly"]', 0, 'Prefix "re-": "Rebuild" = build again after destruction. "Re-" indicates doing something again.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "dishonest" mean?', '["Not honest", "Very honest", "Honest again", "Honest before"]', 0, 'Prefix "dis-": "Dishonest" = not honest or lying. "Dis-" creates the opposite meaning.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "unfair" mean?', '["Not fair", "Very fair", "Fair again", "Fair before"]', 0, 'Prefix "un-": "Unfair" = not fair or unjust. "Un-" reverses the meaning to its opposite.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "prepaid" mean?', '["Paid before", "Not paid", "Paid again", "Paid badly"]', 0, 'Prefix "pre-": "Prepaid" = paid in advance or before use. "Pre-" indicates time before.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Choose the correct word: He had to ____ the exam because he failed. (take again)', '["Retake", "Untake", "Pretake", "Distake"]', 0, 'Prefix application: "Retake" means to take the exam again. "Re-" is used for repetition.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Choose the correct word: It is ____ to drive without a license. (not legal)', '["Illegal", "Relegal", "Prelegal", "Dislegal"]', 0, 'Prefix application: "Illegal" means not legal or against the law. "Il-" (variant of "in-") means not. Note: This uses "il-" instead of "un-" due to pronunciation.', 'medium'),

('foundation', 'word-formation', 'intermediate', 'Which prefix means "not" or "opposite": un-, re-, pre-, or dis-?', '["Both un- and dis-", "Only re-", "Only pre-", "None of them"]', 0, 'Prefix understanding: Both "un-" and "dis-" mean "not" or "opposite". "Re-" means again, "pre-" means before.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'Add the correct prefix: ____ arrange (to arrange again in a different way)', '["Re", "Un", "Pre", "Dis"]', 0, 'Prefix choice: "Rearrange" means to arrange again or organize differently. "Re-" indicates doing something again.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'Add the correct prefix: ____ comfortable (not comfortable)', '["Un", "Re", "Pre", "Dis"]', 0, 'Prefix choice: "Uncomfortable" means not comfortable or causing discomfort. "Un-" creates the opposite.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What does "disconnect" mean?', '["Break the connection", "Connect again", "Connect before", "Connect well"]', 0, 'Prefix "dis-": "Disconnect" = break or remove a connection. "Dis-" indicates reversal of action.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What does "prehistoric" mean?', '["Before recorded history", "Not historic", "Historic again", "Very historic"]', 0, 'Prefix "pre-": "Prehistoric" = before written history or very ancient times. "Pre-" indicates time before history was recorded.', 'hard'),

-- Subtopic 2: Suffixes (-ly, -ness, -ful, -less) (25Q) - 10 easy, 10 medium, 5 hard
('foundation', 'word-formation', 'intermediate', 'Add the suffix "-ly" to "quick". What does "quickly" mean?', '["In a quick way", "Not quick", "Very quick", "Before quick"]', 0, 'Suffix "-ly": Turns adjectives into adverbs. Quickly = in a quick way or fast. It describes how an action is done.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Add the suffix "-ness" to "happy". What does "happiness" mean?', '["State of being happy", "Not happy", "Very happy", "Always happy"]', 0, 'Suffix "-ness": Turns adjectives into nouns. Happiness = the state or quality of being happy. It names a feeling or condition.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Add the suffix "-ful" to "care". What does "careful" mean?', '["Full of care", "Without care", "Not care", "Before care"]', 0, 'Suffix "-ful": Means "full of". Careful = full of care or cautious. It describes having a quality.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Add the suffix "-less" to "care". What does "careless" mean?', '["Without care", "Full of care", "Very care", "Again care"]', 0, 'Suffix "-less": Means "without". Careless = without care or not careful. It describes lacking a quality.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: slow + ly = ?', '["Slowly", "Slowness", "Slowful", "Slowless"]', 0, 'Word formation: "slow" + "-ly" = "slowly". This adverb means in a slow manner.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: dark + ness = ?', '["Darkness", "Darkly", "Darkful", "Darkless"]', 0, 'Word formation: "dark" + "-ness" = "darkness". This noun means the state of being dark or absence of light.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: hope + ful = ?', '["Hopeful", "Hopefully", "Hopeness", "Hopeless"]', 0, 'Word formation: "hope" + "-ful" = "hopeful". This adjective means full of hope or optimistic.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Choose the word: home + less = ?', '["Homeless", "Homeful", "Homeness", "Homely"]', 0, 'Word formation: "home" + "-less" = "homeless". This adjective means without a home or living on streets.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What does "sadly" mean?', '["In a sad way", "State of sadness", "Full of sad", "Without sad"]', 0, 'Suffix "-ly": "Sadly" = in a sad manner. The suffix "-ly" creates an adverb describing how something is done.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What does "kindness" mean?', '["Quality of being kind", "In a kind way", "Full of kind", "Without kind"]', 0, 'Suffix "-ness": "Kindness" = the quality of being kind. The suffix "-ness" creates a noun from an adjective.', 'easy'),

('foundation', 'word-formation', 'intermediate', 'Add the correct suffix to make an adverb: loud____ (in a loud way)', '["Ly", "Ness", "Ful", "Less"]', 0, 'Suffix choice: "Loudly" means in a loud manner. "-ly" turns adjectives into adverbs.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Add the correct suffix to make a noun: weak____ (state of being weak)', '["Ness", "Ly", "Ful", "Less"]', 0, 'Suffix choice: "Weakness" means the state of being weak. "-ness" turns adjectives into nouns.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Add the correct suffix: use____ (full of use or helpful)', '["Ful", "Less", "Ly", "Ness"]', 0, 'Suffix choice: "Useful" means full of use or helpful. "-ful" means "full of" a quality.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Add the correct suffix: fear____ (without fear)', '["Less", "Ful", "Ly", "Ness"]', 0, 'Suffix choice: "Fearless" means without fear or brave. "-less" means "without" a quality.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "beautiful" mean?', '["Full of beauty", "Without beauty", "In a beauty way", "State of beauty"]', 0, 'Suffix "-ful": "Beautiful" = full of beauty or attractive. "-ful" indicates possessing a quality.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "helpless" mean?', '["Without help", "Full of help", "In a help way", "State of help"]', 0, 'Suffix "-less": "Helpless" = without help or unable to help oneself. "-less" indicates absence of a quality.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "softness" mean?', '["Quality of being soft", "In a soft way", "Full of soft", "Without soft"]', 0, 'Suffix "-ness": "Softness" = the quality of being soft. "-ness" creates a noun describing a state.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "greatly" mean?', '["In a great way", "State of great", "Full of great", "Without great"]', 0, 'Suffix "-ly": "Greatly" = in a great manner or very much. "-ly" creates an adverb from an adjective.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Choose the correct word: She spoke ____. (in a quiet way)', '["Quietly", "Quietness", "Quietful", "Quietless"]', 0, 'Suffix application: "Quietly" means in a quiet manner. We need an adverb (-ly) to describe how she spoke.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Choose the correct word: This is a ____ situation. (full of hope)', '["Hopeful", "Hopefully", "Hopeness", "Hopeless"]', 0, 'Suffix application: "Hopeful" means full of hope. We need an adjective (-ful) to describe the situation.', 'medium'),

('foundation', 'word-formation', 'intermediate', 'Which suffix changes an adjective to an adverb?', '["Ly", "Ness", "Ful", "Less"]', 0, 'Suffix understanding: "-ly" changes adjectives to adverbs (quick → quickly). "-ness" makes nouns, "-ful" and "-less" make adjectives.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'Which two suffixes have opposite meanings?', '["Ful and less", "Ly and ness", "Ful and ly", "Ness and less"]', 0, 'Suffix understanding: "-ful" (full of) and "-less" (without) are opposites. Care-ful vs care-less show this contrast.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'Add the correct suffix: thought____ (full of thought or considerate)', '["Ful", "Less", "Ly", "Ness"]', 0, 'Suffix choice: "Thoughtful" means full of thought or considerate of others. "-ful" indicates having a quality.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What does "effortless" mean?', '["Without effort or easy", "Full of effort", "In an effort way", "State of effort"]', 0, 'Suffix "-less": "Effortless" = without effort, easy, or requiring no work. "-less" indicates absence.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What is the difference: "careful" vs "carefully"?', '["Careful is adjective, carefully is adverb", "Both are adjectives", "Both are adverbs", "Both are nouns"]', 0, 'Suffix understanding: "Careful" (adjective with -ful) describes a noun. "Carefully" (adverb with -ly) describes a verb. Example: careful student vs. study carefully.', 'hard'),

-- Subtopic 3: Root Words (25Q) - 10 easy, 10 medium, 5 hard
('foundation', 'word-formation', 'intermediate', 'What is the root word in "teacher"?', '["Teach", "Tea", "Cher", "Er"]', 0, 'Root word: "Teach" is the root. "Teacher" = teach + er (suffix meaning "one who"). The root carries the main meaning.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "playing"?', '["Play", "Ing", "Lay", "Paying"]', 0, 'Root word: "Play" is the root. "Playing" = play + ing (suffix showing continuous action). The root is the base form of the verb.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "unhappy"?', '["Happy", "Un", "Hap", "Unhap"]', 0, 'Root word: "Happy" is the root. "Unhappy" = un (prefix) + happy. Remove the prefix to find the root.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "walked"?', '["Walk", "Ed", "Ked", "Wal"]', 0, 'Root word: "Walk" is the root. "Walked" = walk + ed (suffix showing past tense). The root is the base verb.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "quickly"?', '["Quick", "Ly", "Ick", "Quick"]', 0, 'Root word: "Quick" is the root. "Quickly" = quick + ly (suffix making adverb). Remove the suffix to find the root.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "careful"?', '["Care", "Ful", "Car", "Careful"]', 0, 'Root word: "Care" is the root. "Careful" = care + ful (suffix meaning "full of"). The root carries the core meaning.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "rewrite"?', '["Write", "Re", "Rite", "Rewrite"]', 0, 'Root word: "Write" is the root. "Rewrite" = re (prefix) + write. Remove the prefix to find the root.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "books"?', '["Book", "S", "Boo", "Oks"]', 0, 'Root word: "Book" is the root. "Books" = book + s (suffix for plural). Remove the plural marker to find the root.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "smaller"?', '["Small", "Er", "Smal", "Smaller"]', 0, 'Root word: "Small" is the root. "Smaller" = small + er (suffix for comparison). Remove the comparative suffix to find the root.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "darkness"?', '["Dark", "Ness", "Dar", "Darknes"]', 0, 'Root word: "Dark" is the root. "Darkness" = dark + ness (suffix making noun). The root is the base adjective.', 'easy'),

('foundation', 'word-formation', 'intermediate', 'What is the root word in "disconnected"?', '["Connect", "Disconnect", "Ed", "Dis"]', 0, 'Root word: "Connect" is the root. "Disconnected" = dis (prefix) + connect + ed (suffix). Remove both prefix and suffix.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "beautiful"?', '["Beauty", "Ful", "Beaut", "Beautiful"]', 0, 'Root word: "Beauty" is the root (noun). "Beautiful" = beauty + ful (suffix). Note: "y" changes to "i" when adding "-ful".', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "happiness"?', '["Happy", "Ness", "Happi", "Hap"]', 0, 'Root word: "Happy" is the root. "Happiness" = happy + ness. Note: "y" changes to "i" when adding "-ness".', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "uncomfortable"?', '["Comfort", "Un", "Able", "Comfortable"]', 0, 'Root word: "Comfort" is the root. "Uncomfortable" = un (prefix) + comfort + able (suffix). Remove prefix and suffix.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "running"?', '["Run", "Ning", "Runn", "Running"]', 0, 'Root word: "Run" is the root. "Running" = run + ning. Note: the final "n" doubles before adding "-ing".', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "singer"?', '["Sing", "Er", "Sin", "Ger"]', 0, 'Root word: "Sing" is the root. "Singer" = sing + er (one who sings). Remove the suffix to find the root verb.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "biggest"?', '["Big", "Est", "Bigg", "Gest"]', 0, 'Root word: "Big" is the root. "Biggest" = big + est (superlative suffix). Note: final consonant doubles.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "graceful"?', '["Grace", "Ful", "Grac", "Graceful"]', 0, 'Root word: "Grace" is the root (noun). "Graceful" = grace + ful (full of grace). The root provides the core meaning.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "preview"?', '["View", "Pre", "Review", "Vie"]', 0, 'Root word: "View" is the root. "Preview" = pre (prefix meaning before) + view. Remove the prefix.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "hopeless"?', '["Hope", "Less", "Hop", "Hopeles"]', 0, 'Root word: "Hope" is the root. "Hopeless" = hope + less (without hope). Remove the suffix.', 'medium'),

('foundation', 'word-formation', 'intermediate', 'What is the root word in "unpredictable"?', '["Predict", "Un", "Able", "Predictable"]', 0, 'Root word: "Predict" is the root verb. "Unpredictable" = un (prefix) + predict + able (suffix). Remove both affixes.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "impossibility"?', '["Possible", "Im", "Ity", "Impossible"]', 0, 'Root word: "Possible" is the root. "Impossibility" = im (prefix) + possible + ity (suffix). The root is the core adjective.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "misunderstanding"?', '["Understand", "Mis", "Ing", "Understanding"]', 0, 'Root word: "Understand" is the root verb. "Misunderstanding" = mis (prefix) + understand + ing (suffix). Remove prefix and suffix.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "strengthened"?', '["Strong", "En", "Ed", "Strength"]', 0, 'Root word: "Strong" is the original root. "Strengthened" comes from strong → strength (noun) → strengthen (verb) → strengthened (past). The ultimate root is "strong".', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What is the root word in "unbelievable"?', '["Believe", "Un", "Able", "Believable"]', 0, 'Root word: "Believe" is the root verb. "Unbelievable" = un (prefix) + believe + able (suffix). The root carries the core meaning.', 'hard'),

-- Subtopic 4: Compound Words (25Q) - 10 easy, 10 medium, 5 hard
('foundation', 'word-formation', 'intermediate', 'Combine: sun + light = ?', '["Sunlight", "Lightsum", "Sunlit", "Lightsun"]', 0, 'Compound word: "Sunlight" combines two words to create new meaning = light from the sun. Compound words join complete words.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: tooth + brush = ?', '["Toothbrush", "Brushtooth", "Teethbrush", "Brushteeth"]', 0, 'Compound word: "Toothbrush" = a brush for cleaning teeth. Two words combine to create a new object.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: rain + coat = ?', '["Raincoat", "Coatrain", "Rainy coat", "Rain coats"]', 0, 'Compound word: "Raincoat" = a coat for protection from rain. The words join to name a specific item.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: book + shelf = ?', '["Bookshelf", "Shelfbook", "Booky shelf", "Shelf books"]', 0, 'Compound word: "Bookshelf" = a shelf for storing books. Compound words create specific meanings.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: foot + ball = ?', '["Football", "Ballfoot", "Footy ball", "Ball foot"]', 0, 'Compound word: "Football" = a ball game played with feet. The compound names a specific sport.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: bed + room = ?', '["Bedroom", "Roombed", "Beddy room", "Room bed"]', 0, 'Compound word: "Bedroom" = a room with a bed for sleeping. Compounds name specific places or things.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: class + room = ?', '["Classroom", "Roomclass", "Classy room", "Room class"]', 0, 'Compound word: "Classroom" = a room where classes are held. The compound specifies the room''s purpose.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: fire + man = ?', '["Fireman", "Manfire", "Firy man", "Man fire"]', 0, 'Compound word: "Fireman" = a man who fights fires (firefighter). The compound creates a job title.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: water + fall = ?', '["Waterfall", "Fallwater", "Watery fall", "Fall water"]', 0, 'Compound word: "Waterfall" = water falling from a height. The compound describes a natural feature.', 'easy'),
('foundation', 'word-formation', 'intermediate', 'Combine: snow + ball = ?', '["Snowball", "Ballsnow", "Snowy ball", "Ball snow"]', 0, 'Compound word: "Snowball" = a ball made of snow. Compounds combine meanings to create new concepts.', 'easy'),

('foundation', 'word-formation', 'intermediate', 'What does "airport" mean?', '["A port for air travel", "Air in a port", "Portable air", "Airy port"]', 0, 'Compound meaning: "Airport" = air + port = a place where aircraft land and take off. Analyze each part for meaning.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "homework" mean?', '["Work done at home", "Home at work", "Working home", "Home for work"]', 0, 'Compound meaning: "Homework" = home + work = school work done at home. The first word modifies the second.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "greenhouse" mean?', '["A house for growing plants", "A green-colored house", "A house made of green", "Green at house"]', 0, 'Compound meaning: "Greenhouse" = green + house = a glass building for growing plants. The meaning is specific, not literal green + house.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "birthday" mean?', '["Day of birth", "Birth on a day", "Daily birth", "Day for birth"]', 0, 'Compound meaning: "Birthday" = birth + day = the anniversary of the day someone was born. Compounds can show relationships.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "toothpaste" mean?', '["Paste for cleaning teeth", "Paste made of teeth", "Teeth in paste", "Pasty teeth"]', 0, 'Compound meaning: "Toothpaste" = tooth + paste = paste used for cleaning teeth. The first word shows purpose.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Combine: eye + brow = ?', '["Eyebrow", "Broweye", "Eyey brow", "Brow eye"]', 0, 'Compound word: "Eyebrow" = the line of hair above the eye. Compounds can name body parts.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Combine: news + paper = ?', '["Newspaper", "Papernews", "Newsy paper", "Paper news"]', 0, 'Compound word: "Newspaper" = paper containing news. The compound names a specific publication type.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Combine: grand + mother = ?', '["Grandmother", "Mothergrand", "Grandy mother", "Mother grand"]', 0, 'Compound word: "Grandmother" = mother of one''s parent. Compounds show family relationships.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'Combine: tooth + ache = ?', '["Toothache", "Achetooth", "Toothed ache", "Ache tooth"]', 0, 'Compound word: "Toothache" = pain in a tooth. The compound describes a specific type of pain.', 'medium'),
('foundation', 'word-formation', 'intermediate', 'What does "fingernail" mean?', '["Nail on a finger", "Finger on a nail", "Nail shaped like finger", "Finger made of nail"]', 0, 'Compound meaning: "Fingernail" = finger + nail = the hard part at the end of a finger. Compounds name specific body parts.', 'medium'),

('foundation', 'word-formation', 'intermediate', 'What type of compound is "breakfast"? (break + fast)', '["A compound with changed meaning", "Same as break plus fast", "Not a compound", "Broken compound"]', 0, 'Compound analysis: "Breakfast" = break + fast (fasting) = the meal that breaks the overnight fast. Historical meaning creates modern word.', 'hard'),
('foundation', 'word-formation', 'intermediate', 'What does "honeymoon" mean?', '["A vacation after wedding", "Moon made of honey", "Honey on the moon", "Sweet moon"]', 0, 'Compound meaning: "Honeymoon" = honey + moon = vacation trip taken by newly married couple. Some compounds have figurative meanings.', 'hard'),
